"use strict";parserFactory.register("storyseedling.com",()=>new StorySeedlingParser);class StorySeedlingParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll("main .grid.w-full a")].map(e=>this.linkToChapter(e))}linkToChapter(e){let t=e.querySelector(".truncate").textContent;return{sourceUrl:e.href,title:t}}findContent(e){return e.querySelector("div.prose .mb-4")||e.querySelector("#chapter-content")}populateUIImpl(){document.getElementById("removeAuthorNotesRow").hidden=!1}preprocessRawDom(e){let t=e.querySelector("div.prose .mb-4:nth-of-type(2)");null==t||this.userPreferences.removeAuthorNotes.value||(this.tagAuthorNotes([t]),this.findContent(e).appendChild(t))}extractTitleImpl(e){return e.querySelector("h1")}extractAuthor(e){let t=e.querySelector("div.leading-7 a");return t?.textContent??super.extractAuthor(e)}findChapterTitle(e){return e.querySelector(".truncate")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"div[x-data='']")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div.order-2.mb-4")]}}